// 1. Configuration
const chunkSize = 1000; // Target characters per chunk
const chunkOverlap = 200; // Overlap to maintain context between chunks
const separators = ["\n\n", "\n", ". ", " ", ""]; // Order of priority for splitting

// 2. Input Data
// Assumes the previous node passed 'text', 'id' (document_id), and 'metadata.'
const text =  $('transform').first().json.original_text ||  "";
const docId = $('Create Document Catalog').first().json.id || null;
const globalMetadata = $('transform').first().json.metadata || {};

/**
 * Recursive Splitter Function
 */
function splitText(text, separators) {
    const finalChunks = [];

    // Start the recursive process
    let currentSeparator = separators[0];
    let nextSeparators = separators.slice(1);

    // Split the text by the current separator
    const parts = text.split(currentSeparator);
    let currentDoc = "";

    for (const part of parts) {
        // If adding this part exceeds chunk size
        if ((currentDoc + part).length > chunkSize) {

            // If currentDoc is not empty, push it as a chunk
            if (currentDoc.length > 0) {
                finalChunks.push(currentDoc.trim());
                // Create overlap: keep the last 'chunkOverlap' characters
                currentDoc = currentDoc.slice(-chunkOverlap);
            }

            // If the single part itself is bigger than chunkSize, recurse deeper
            if (part.length > chunkSize && nextSeparators.length > 0) {
                const subChunks = splitText(part, nextSeparators);
                finalChunks.push(...subChunks.slice(0, -1));
                currentDoc = subChunks.slice(-1)[0];
            } else {
                currentDoc += part + currentSeparator;
            }
        } else {
            currentDoc += part + currentSeparator;
        }
    }

    if (currentDoc.trim().length > 0) {
        finalChunks.push(currentDoc.trim());
    }

    return finalChunks;
}

// 3. Execute Splitting
const allChunks = splitText(text, separators);

// 4. Format Output for n8n
// This returns an array of objects that n8n treats as separate items
return allChunks.map((content, index) => {
    return {
        json: {
            document_id: docId,
            chunk_index: index,
            content: content,
            // Constructing the specific metadata for the document_chunks table
            chunk_metadata: {
                category: globalMetadata.category,
                access_level: globalMetadata.access_level,
                language: globalMetadata.language,
                char_count: content.length,
                is_partial: true
            }
        }
    };
});
